<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const valor=parseFloat(document.getElementById('cm-valor').value);const taxa=parseFloat(document.getElementById('cm-taxa').value);clearError();if(isNaN(valor)||isNaN(taxa)||valor<0||taxa<0){showError('Informe valor e taxa com números válidos.');return;}const aumento=valor*(taxa/100);const total=valor+aumento;document.getElementById('cm-corrigido').textContent='R$ '+fmtBRL(total);document.getElementById('cm-aumento').textContent='R$ '+fmtBRL(aumento);document.getElementById('tool-detail').textContent='Cálculo simples de correção baseado na taxa percentual informada.';showResult('tool-result');}function clearTool(){['cm-valor','cm-taxa'].forEach(id=>document.getElementById(id).value='');['cm-corrigido','cm-aumento'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule a correção antes de copiar o resultado.');return;}copyToClipboard('Valor corrigido: '+document.getElementById('cm-corrigido').textContent,button);}
</script>
